fn binary_search(arr: i64, n: i64, target: i64) -> i64 = {
    let mut left: i64 = 0;
    let mut right: i64 = n - 1;
    let mut result: i64 = -1;
    while left <= right {
        let mid: i64 = left + (right - left) / 2;
        let mid_val: i64 = vec_get(arr, mid);
        if mid_val == target {
            result = mid;
            left = right + 1;
            ()
        } else {
            if mid_val < target {
                left = mid + 1;
                ()
            } else {
                right = mid - 1;
                ()
            };
            ()
        };
        ()
    };
    result
};

